#include "msconnector/decision_action.h"
#include "msconnector/intervention.h"
const char *msconnector_decision_action_name(msconnector_decision_action a) { switch (a) { case MSCONNECTOR_DECISION_ACTION_ALLOW: return "allow"; case MSCONNECTOR_DECISION_ACTION_DENY: return "deny"; case MSCONNECTOR_DECISION_ACTION_REDIRECT: return "redirect"; case MSCONNECTOR_DECISION_ACTION_DROP: return "drop"; case MSCONNECTOR_DECISION_ACTION_LOG_ONLY: return "log_only"; case MSCONNECTOR_DECISION_ACTION_ABORT_CONNECTION: return "abort_connection"; } return "unknown"; }
msconnector_decision_action msconnector_decision_action_from_decision(const msconnector_decision *d) { if (!d) return MSCONNECTOR_DECISION_ACTION_LOG_ONLY; if (d->intervention.redirect_url) return MSCONNECTOR_DECISION_ACTION_REDIRECT; if (msconnector_intervention_is_disruptive(&d->intervention)) return MSCONNECTOR_DECISION_ACTION_DENY; if (d->status == MSCONNECTOR_STATUS_BLOCKED) return MSCONNECTOR_DECISION_ACTION_DENY; return MSCONNECTOR_DECISION_ACTION_ALLOW; }
int msconnector_decision_action_is_disruptive(msconnector_decision_action a) { return a == MSCONNECTOR_DECISION_ACTION_DENY || a == MSCONNECTOR_DECISION_ACTION_REDIRECT || a == MSCONNECTOR_DECISION_ACTION_DROP || a == MSCONNECTOR_DECISION_ACTION_ABORT_CONNECTION; }
